```tsx
import { FspFinancingCaseOverviewSubPageHeader } from "@/layouts/fsp/FspFinancingCaseOverviewSubPageHeader";
import { PropertyManagementCaseDetailsPageSubHeader } from "@/features/propertyManagement/components/PropertyManagementCaseDetailsPageSubHeader";
import { getUpdateReferenceAccountDefaultValues } from "@/features/referenceAccount/forms/updateReferenceAccountForm/getUpdateReferenceAccountDefaultValues";
import { UpdateReferenceAccountForm } from "@/features/referenceAccount/forms/updateReferenceAccountForm/UpdateReferenceAccountForm";
import { fetchWithErrorHandling } from "@/shared/backend/fetchWithErrorHandling";
import { getReferenceAccount } from "@/shared/backend/models/referenceAccount/server";
import { Constants } from "@/shared/utils/constants";
import {
  FormLayout,
  FormLayoutArea,
} from "@finstreet/ui/components/pageLayout/Layout/FormLayout";
import { PageContent } from "@finstreet/ui/components/pageLayout/PageContent";
import { Metadata } from "next";
import { getTranslations } from "next-intl/server";

export const metadata: Metadata = {
  title: `Verrechnungskonto | ${Constants.companyName}`,
};

type FSPHoaAccountFinancingCaseReferenceAccountPageProps = {
  params: Promise<{ financingCaseId: string }>;
};

export default async function FSPHoaAccountFinancingCaseReferenceAccountPage({
  params,
}: FSPHoaAccountFinancingCaseReferenceAccountPageProps) {
  const t = await getTranslations("referenceAccount");
  const { financingCaseId } = await params;

  const referenceAccountResponse = await fetchWithErrorHandling(() =>
    getReferenceAccount({
      pathVariables: { financingCaseId },
    }),
  );

  const defaultValues = getUpdateReferenceAccountDefaultValues({
    financingCaseId,
    referenceAccountResponse,
  });

  return (
    <>
      <FspFinancingCaseOverviewSubPageHeader
        title={t("updateReferenceAccountForm.title")}
        financingCaseId={financingCaseId}
        header={referenceAccountResponse.header}
      />
      <PageContent>
        <FormLayout>
          <FormLayoutArea gridArea={"form"}>
            <UpdateReferenceAccountForm
              defaultValues={defaultValues}
              portal="operations"
              editable={referenceAccountResponse.flags.editable}
            />
          </FormLayoutArea>
        </FormLayout>
      </PageContent>
    </>
  );
}
```

